part of '../app_router.dart';

String _buildRoleSelectRoute({
  bool manual = false,
}) {
  return Uri(
    path: AppRoutePath.roleSelect,
    queryParameters: <String, String>{
      if (manual) _roleSelectManualQueryKey: '1',
    },
  ).toString();
}

String _joinRoleToQuery(JoinRole role) {
  return switch (role) {
    JoinRole.driver => 'driver',
    JoinRole.guest => 'guest',
    JoinRole.passenger || JoinRole.unknown => 'passenger',
  };
}

String _buildJoinRoute({required JoinRole role}) {
  return Uri(
    path: AppRoutePath.join,
    queryParameters: <String, String>{
      _joinRoleQueryKey: _joinRoleToQuery(role),
    },
  ).toString();
}

String _buildJoinQrRoute({required JoinRole role}) {
  return Uri(
    path: AppRoutePath.joinQr,
    queryParameters: <String, String>{
      _joinRoleQueryKey: _joinRoleToQuery(role),
    },
  ).toString();
}

String _buildJoinSuccessRoute({
  required JoinRole role,
  required String nextPath,
}) {
  return Uri(
    path: AppRoutePath.joinSuccess,
    queryParameters: <String, String>{
      _joinRoleQueryKey: _joinRoleToQuery(role),
      _joinNextPathQueryKey: nextPath,
    },
  ).toString();
}

String _buildJoinErrorRoute({
  required JoinRole role,
  required String reason,
}) {
  return Uri(
    path: AppRoutePath.joinError,
    queryParameters: <String, String>{
      _joinRoleQueryKey: _joinRoleToQuery(role),
      _joinErrorReasonQueryKey: reason,
    },
  ).toString();
}

String? _resolveAuthNextRole(String? raw) {
  final normalized = raw?.trim().toLowerCase();
  switch (normalized) {
    case _authNextRolePassenger:
    case _authNextRoleDriver:
      return normalized;
    default:
      return null;
  }
}

String _resolveAuthEmailMode(String? raw) {
  final normalized = raw?.trim().toLowerCase();
  if (normalized == _authEmailModeRegister) {
    return _authEmailModeRegister;
  }
  if (normalized == _authEmailModeForgot) {
    return _authEmailModeForgot;
  }
  return _authEmailModeSignIn;
}

String? _resolveSignedInLandingFromUserRole(UserRole role) {
  switch (role) {
    case UserRole.driver:
      return _roleCorridorCoordinator.homePathForRole(role);
    case UserRole.passenger:
      return _roleCorridorCoordinator.homePathForRole(role);
    case UserRole.guest:
      return _buildJoinRoute(role: JoinRole.guest);
    case UserRole.unknown:
      final user = FirebaseAuth.instance.currentUser;
      if (user != null && user.isAnonymous) {
        return _buildJoinRoute(role: JoinRole.guest);
      }
      return null;
  }
}

String? _resolveSignedInLandingFromRoleString(String? role) {
  final parsedRole = _resolveRoleFromRawString(role);
  if (parsedRole == UserRole.unknown) {
    return null;
  }
  return _resolveSignedInLandingFromUserRole(parsedRole);
}

String _resolveRoleCorridorFallbackLocation(UserRole role) {
  if (role == UserRole.guest) {
    return _buildJoinRoute(role: JoinRole.guest);
  }
  return _roleCorridorCoordinator.homePathForRole(role);
}

UserRole _snapshotRoleSwitchSourceRole() {
  if (_sessionPreferredRole == UserRole.driver ||
      _sessionPreferredRole == UserRole.passenger ||
      _sessionPreferredRole == UserRole.guest) {
    return _sessionPreferredRole;
  }
  return UserRole.unknown;
}

String _readCurrentMatchedLocationForRoleSwitch(BuildContext context) {
  try {
    return GoRouterState.of(context).matchedLocation;
  } catch (_) {
    return AppRoutePath.roleSelect;
  }
}

void _applyRoleSwitchNavigationPlan(
  BuildContext context, {
  required UserRole fromRole,
  required UserRole toRole,
  required String targetLocation,
}) {
  final currentLocation = _readCurrentMatchedLocationForRoleSwitch(context);
  final plan = _roleCorridorCoordinator.planRoleSwitchToDestination(
    fromRole: fromRole,
    toRole: toRole,
    currentLocation: currentLocation,
    targetLocation: targetLocation,
  );

  roleCorridorShellTransitionBus.publish(
    fromRole: fromRole,
    toRole: toRole,
    currentLocation: currentLocation,
    plan: plan,
  );

  // Shells now receive transition metadata; navigation behavior stays unchanged.
  context.go(plan.targetLocation);
}

UserRole _resolveRoleFromRawString(String? role) {
  switch (role?.trim().toLowerCase()) {
    case 'driver':
      return UserRole.driver;
    case 'passenger':
      return UserRole.passenger;
    case 'guest':
      return UserRole.guest;
    default:
      return UserRole.unknown;
  }
}

