String _buildAuthRouteWithNextRole(String role) {
  return Uri(
    path: AppRoutePath.auth,
    queryParameters: <String, String>{
      _authNextRoleQueryKey: role,
    },
  ).toString();
}

String _buildAuthRoute({String? nextRole}) {
  final normalizedNextRole = _resolveAuthNextRole(nextRole);
  return Uri(
    path: AppRoutePath.auth,
    queryParameters: <String, String>{
      if (normalizedNextRole != null) _authNextRoleQueryKey: normalizedNextRole,
    },
  ).toString();
}

String _buildEmailAuthRoute({
  required String mode,
  String? nextRole,
}) {
  final normalizedNextRole = _resolveAuthNextRole(nextRole);
  return Uri(
    path: AppRoutePath.authEmail,
    queryParameters: <String, String>{
      _authEmailModeQueryKey: _resolveAuthEmailMode(mode),
      if (normalizedNextRole != null) _authNextRoleQueryKey: normalizedNextRole,
    },
  ).toString();
}

String _buildPaywallRouteWithSource(String source) {
  return Uri(
    path: AppRoutePath.paywall,
    queryParameters: <String, String>{
      'source': source,
    },
  ).toString();
}

String _buildDriverTripCompletedRoute({
  required String routeId,
  required String tripId,
  required String routeName,
}) {
  return Uri(
    path: AppRoutePath.driverTripCompleted,
    queryParameters: <String, String>{
      'routeId': routeId,
      'tripId': tripId,
      'routeName': routeName,
    },
  ).toString();
}

String _buildDriverHomeRoute({
  String? previewRouteId,
  String? startedRouteId,
  bool forceRefresh = false,
}) {
  final query = <String, String>{};
  final normalizedPreviewRouteId = _nullableParam(previewRouteId);
  if (normalizedPreviewRouteId != null) {
    query['previewRouteId'] = normalizedPreviewRouteId;
  }
  final normalizedStartedRouteId = _nullableParam(startedRouteId);
  if (normalizedStartedRouteId != null) {
    query['startedRouteId'] = normalizedStartedRouteId;
  }
  if (forceRefresh) {
    query['refresh'] = DateTime.now().millisecondsSinceEpoch.toString();
  }
  if (query.isEmpty) {
    return AppRoutePath.driverHome;
  }
  return Uri(
    path: AppRoutePath.driverHome,
    queryParameters: query,
  ).toString();
}
